    problematic_mods = []
    for (old, new) in ppt_diff.modified_slides:
        if old.slide_number != 5:
            # Check if nontrivial changes happened
            major = False
            # Check notes, title, number of elements (as proxy)
            if old.title != new.title or (old.notes or "") != (new.notes or "") or old.element_count != new.element_count:
                major = True
            if major:
                problematic_mods.append(old.slide_number)
    # Check for added/removed slides
    added = [s.slide_number for s in ppt_diff.added_slides if s.slide_number != 5]
    removed = [s.slide_number for s in ppt_diff.removed_slides if s.slide_number != 5]
    if problematic_mods or added or removed:
        return f"Slides other than 5 changed: modified={problematic_mods}, added={added}, removed={removed}.", 0.0
    return "No extraneous changes to other slides.", 1.0

def compute_score() -> tuple[str, float]:
    # Use VLM to compare before/after slide 5 prominence
    orig_img = None
    mod_img = None
    for s in original_ppt_screenshots:
        if s.slide_number == 5:
            orig_img = s.image_path
            break
    for s in modified_ppt_screenshots:
        if s.slide_number == 5:
            mod_img = s.image_path
            break
    if not orig_img or not mod_img:
        return "Slide 5 screenshot missing.", 0.0
    prompt = (
        "Given these two screenshots of the same PowerPoint slide before and after image resizing operation, do the smaller images crowd out the main chart?\n" 
        "Answer YES or NO and explain."
    )
    result = vlm_call(prompt, [orig_img, mod_img], temperature=0.0, max_tokens=5)
    if 'YES' in result.upper():
        return f"VLM confirms smaller images crowd out the main chart.", 0.0
    elif 'NO' in result.upper():
        return f"VLM confirms smaller images do not crowd out the main chart.", 1.0
    else:
        return f"Ambiguous VLM result: {result}", 0.5
